var SCHEMA_LOCAL_PUSH_AUDIT_ENVELOPE = {
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ferros.local/schemas/local-push-audit-envelope.schema.json",
  "title": "FERROS Local Push Audit Envelope",
  "description": "Canonical additive local-only envelope for bounded push digests and runway observation records. This surface keeps local sovereignty, explicit operator consent, and auditable handoff metadata explicit without widening frozen profile or capability-grant contracts.",
  "type": "object",
  "required": [
    "envelopeVersion",
    "envelopeType",
    "createdAt",
    "authority",
    "scope",
    "artifacts"
  ],
  "additionalProperties": false,
  "properties": {
    "envelopeVersion": {
      "type": "string",
      "pattern": "^\\d+\\.\\d+$"
    },
    "envelopeType": {
      "type": "string",
      "enum": ["local-push", "local-audit"],
      "description": "Classifies whether the envelope summarizes a local push digest or a local audit handoff."
    },
    "createdAt": {
      "type": "string",
      "format": "date-time"
    },
    "authority": {
      "$ref": "#/$defs/authority"
    },
    "scope": {
      "$ref": "#/$defs/scope"
    },
    "artifacts": {
      "type": "array",
      "minItems": 1,
      "items": {
        "$ref": "#/$defs/artifact"
      }
    },
    "digests": {
      "type": "array",
      "description": "Optional future digest attachments for per-batch or per-artifact integrity summaries.",
      "items": {
        "$ref": "#/$defs/digest"
      }
    },
    "observations": {
      "type": "array",
      "description": "Optional future runway-observation records tied to the local envelope scope.",
      "items": {
        "$ref": "#/$defs/observation"
      }
    },
    "notes": {
      "type": "array",
      "items": {
        "type": "string"
      }
    }
  },
  "$defs": {
    "authority": {
      "type": "object",
      "required": ["mode", "consent"],
      "additionalProperties": false,
      "properties": {
        "mode": {
          "const": "local-only",
          "description": "Hosted or remote authority is not implied by this envelope."
        },
        "consent": {
          "const": "explicit-operator-consent",
          "description": "Privileged publication or capture must stay operator-armed."
        }
      }
    },
    "scope": {
      "type": "object",
      "required": ["stream", "surface", "reason"],
      "additionalProperties": false,
      "properties": {
        "batchId": {
          "type": "string"
        },
        "waveId": {
          "type": "string"
        },
        "laneId": {
          "type": "string"
        },
        "stream": {
          "type": "string",
          "pattern": "^S[1-8]$"
        },
        "surface": {
          "type": "string",
          "enum": ["push-digest", "runway-observation", "audit-trace"]
        },
        "reason": {
          "type": "string",
          "minLength": 1
        }
      }
    },
    "artifact": {
      "type": "object",
      "required": ["path", "role"],
      "additionalProperties": false,
      "properties": {
        "path": {
          "type": "string",
          "pattern": "^(?!/)(?![A-Za-z]:).+"
        },
        "role": {
          "type": "string",
          "enum": ["anchor", "input", "output", "evidence"]
        },
        "digestRef": {
          "type": ["string", "null"],
          "description": "Optional label matching a digest entry when one is present."
        }
      }
    },
    "digest": {
      "type": "object",
      "required": ["label", "algorithm", "value"],
      "additionalProperties": false,
      "properties": {
        "label": {
          "type": "string",
          "minLength": 1
        },
        "algorithm": {
          "type": "string",
          "enum": ["sha256", "blake3", "other"]
        },
        "value": {
          "type": "string",
          "minLength": 1
        }
      }
    },
    "observation": {
      "type": "object",
      "required": ["target", "status"],
      "additionalProperties": false,
      "properties": {
        "target": {
          "type": "string",
          "minLength": 1
        },
        "status": {
          "type": "string",
          "enum": ["planned", "observed", "deferred"]
        },
        "summary": {
          "type": "string"
        }
      }
    }
  }
};

// Source: schemas/onramp-proposal.schema.json
var SCHEMA_ONRAMP_PROPOSAL = {
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ferros.local/schemas/onramp-proposal.schema.json",
  "title": "FERROS Local Onramp Proposal",
  "description": "Bounded local-only, non-evidentiary proposed-material artifact emitted by ferros-hub during the local onramp rehearsal path. This proposal remains quarantined pending consent and is not canonical FERROS state, a grant, or a partner-facing contract.",
  "type": "object",
  "required": [
    "source",
    "proposalId",
    "bridgeAgentName",
    "standInEntityName",
    "requestedCapability",
    "requestedAction",
    "quarantineStatus",
    "scope",
    "evidence",
    "localArtifactPath"
  ],
  "additionalProperties": false,
  "properties": {
    "source": {
      "$ref": "#/$defs/safeHubPath"
    },
    "proposalId": {
      "$ref": "#/$defs/safeSlug"
    },
    "bridgeAgentName": {
      "$ref": "#/$defs/safeSlug"
    },
    "standInEntityName": {
      "$ref": "#/$defs/safeSlug"
    },
    "requestedCapability": {
      "$ref": "#/$defs/safeCapability"
    },
    "requestedAction": {
      "$ref": "#/$defs/safeSlug"
    },
    "quarantineStatus": {
      "const": "quarantined-pending-consent"
    },
    "scope": {
      "const": "local-only"
    },
    "evidence": {
      "const": "non-evidentiary"
    },
    "localArtifactPath": {
      "$ref": "#/$defs/safeHubPath"
    }
  },
  "$defs": {
    "safeSlug": {
      "type": "string",
      "minLength": 1,
      "pattern": "^(?!.*(?:[Hh][Aa][Rr][Dd][Ww][Aa][Rr][Ee]|[Pp][Rr][Oo][Oo][Ff]|[Ll][Aa][Uu][Nn][Cc][Hh]|[Aa][Cc][Cc][Ee][Pp][Tt][Ee][Dd]|[Cc][Aa][Nn][Oo][Nn][Ii][Cc][Aa][Ll]|[Gg][Rr][Aa][Nn][Tt][Ee][Dd]))[a-z0-9-]+$"
    },
    "safeCapability": {
      "type": "string",
      "minLength": 1,
      "pattern": "^(?!.*://)(?!.*(?:[Hh][Aa][Rr][Dd][Ww][Aa][Rr][Ee]|[Pp][Rr][Oo][Oo][Ff]|[Ll][Aa][Uu][Nn][Cc][Hh]|[Aa][Cc][Cc][Ee][Pp][Tt][Ee][Dd]|[Cc][Aa][Nn][Oo][Nn][Ii][Cc][Aa][Ll]|[Gg][Rr][Aa][Nn][Tt][Ee][Dd]))[a-z0-9.-]+$"
    },
    "safeHubPath": {
      "type": "string",
      "pattern": "^(?!.*://)(?!.*:)(?!.*(?:^|/)\\.\\.(?:/|$))(?!.*(?:[Hh][Aa][Rr][Dd][Ww][Aa][Rr][Ee]|[Pp][Rr][Oo][Oo][Ff]|[Ll][Aa][Uu][Nn][Cc][Hh]|[Aa][Cc][Cc][Ee][Pp][Tt][Ee][Dd]|[Cc][Aa][Nn][Oo][Nn][Ii][Cc][Aa][Ll]|[Gg][Rr][Aa][Nn][Tt][Ee][Dd]))\\.tmp/hub/.+\\.json$"
    }
  }
};

// Source: schemas/profile.schema.json
var SCHEMA_PROFILE = {
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ferros.local/schemas/profile.schema.json",
  "title": "FERROS Profile",
  "description": "Canonical schema for a FERROS user profile stored in localStorage under ferros_profile. Version 1.0 (Phase 0).",
  "type": "object",
  "required": ["meta", "identity", "attributes", "skills", "achievements", "journal", "credentials", "sealChain"],
  "additionalProperties": false,
  "properties": {
    "meta": { "$ref": "#/$defs/meta" },
    "identity": { "$ref": "#/$defs/identity" },
    "attributes": { "$ref": "#/$defs/attributes" },
    "skills": { "$ref": "#/$defs/skills" },
    "achievements": {
      "type": "array",
      "items": { "$ref": "#/$defs/achievement" }
    },
    "journal": {
      "type": "array",
      "items": { "$ref": "#/$defs/journalEntry" }
    },
    "credentials": {
      "type": "array",
      "items": { "$ref": "#/$defs/credential" }
    },
    "sealChain": {
      "type": "array",
      "items": { "$ref": "#/$defs/seal" }
    },
    "auditTrail": {
      "type": "array",
      "description": "C10 bounded audit ring buffer. Cap: 1000 entries, FIFO eviction.",
      "items": { "$ref": "#/$defs/auditEntry" }
    },
    "schedule": {
      "type": "object",
      "description": "V2 migration field: user schedule state. Added by migrateProfileStructure().",
      "properties": {
        "archetype": { "type": ["string", "null"] },
        "activeDeck": { "type": ["string", "null"] },
        "wakeTime": { "type": "string" },
        "sleepTime": { "type": "string" },
        "slots": { "type": "array" }
      }
    },
    "completions": {
      "type": "object",
      "description": "V2 migration field: protocol completion tracking. Added by migrateProfileStructure()."
    },
    "creditLog": {
      "type": "object",
      "description": "V2 migration field: XP credit history. Added by migrateProfileStructure()."
    },
    "bag": {
      "type": "array",
      "description": "V2 migration field: inventory bag. Added by migrateProfileStructure().",
      "items": { "type": "object" }
    }
  },
  "$defs": {
    "meta": {
      "type": "object",
      "required": ["version", "created", "lastModified", "assistanceLevel", "genesisHash", "currentSeal", "sealCount", "stage"],
      "additionalProperties": false,
      "properties": {
        "version": { "type": "string", "pattern": "^\\d+\\.\\d+$" },
        "created": { "type": ["string", "null"], "format": "date-time" },
        "lastModified": { "type": ["string", "null"], "format": "date-time" },
        "assistanceLevel": { "type": "integer", "minimum": 1, "maximum": 4 },
        "genesisHash": { "type": ["string", "null"] },
        "currentSeal": { "type": ["string", "null"] },
        "sealCount": { "type": "integer", "minimum": 0 },
        "stage": { "type": "integer", "minimum": 0, "maximum": 4 },
        "anchoredToLedger": { "type": "boolean", "default": false },
        "ledgerTxHash": { "type": ["string", "null"], "default": null },
        "schemaVersion": { "type": "integer", "description": "Internal structural version used by migrateProfileStructure(). Distinct from meta.version (interchange version)." },
        "claimedAliasSessions": { "type": "array", "items": { "type": "string" }, "default": [], "description": "Canonical dedupe index for claimed alias/recovery log sessions." },
        "xp": { "type": "integer", "minimum": 0, "default": 0, "description": "Cumulative XP from alias/recovery log claims." },
        "sealBroken": { "type": "boolean", "default": false, "description": "True if imported profile had a broken seal chain." },
        "revision": { "type": "integer", "minimum": 0, "default": 0, "description": "Monotonically increasing counter for cross-tab coordination." }
      }
    },
    "identity": {
      "type": "object",
      "required": ["name", "avatar", "class", "streamAffinity", "title", "joinedDate", "streakDays", "longestStreak"],
      "additionalProperties": false,
      "properties": {
        "name": { "type": "string" },
        "avatar": { "type": "string" },
        "class": { "type": ["string", "null"], "enum": ["Architect", "Engineer", "Scholar", "Artisan", "Healer", "Guardian", "Guided", "Community", null] },
        "streamAffinity": { "type": ["string", "null"], "enum": ["A", "B", "C", null] },
        "title": { "type": "string" },
        "joinedDate": { "type": ["string", "null"], "format": "date-time" },
        "streakDays": { "type": "integer", "minimum": 0 },
        "longestStreak": { "type": "integer", "minimum": 0 },
        "archetype": { "type": ["string", "null"] },
        "wakeTime": { "type": "string" },
        "sleepTime": { "type": "string" },
        "categoryInterests": { "type": "array", "items": { "type": "string" } }
      }
    },
    "attribute": {
      "type": "object",
      "required": ["level", "xp", "xpToNext", "color", "icon"],
      "additionalProperties": false,
      "properties": {
        "level": { "type": "integer", "minimum": 1 },
        "xp": { "type": "integer", "minimum": 0 },
        "xpToNext": { "type": "integer", "minimum": 1 },
        "color": { "type": "string" },
        "icon": { "type": "string" }
      }
    },
    "attributes": {
      "type": "object",
      "required": ["Discipline", "Knowledge", "Craft", "Governance", "Wellness", "Community"],
      "additionalProperties": false,
      "properties": {
        "Discipline": { "$ref": "#/$defs/attribute" },
        "Knowledge": { "$ref": "#/$defs/attribute" },
        "Craft": { "$ref": "#/$defs/attribute" },
        "Governance": { "$ref": "#/$defs/attribute" },
        "Wellness": { "$ref": "#/$defs/attribute" },
        "Community": { "$ref": "#/$defs/attribute" }
      }
    },
    "skills": {
      "type": "object",
      "required": ["A", "B", "C"],
      "additionalProperties": false,
      "properties": {
        "A": { "type": "array", "items": { "type": "string" } },
        "B": { "type": "array", "items": { "type": "string" } },
        "C": { "type": "array", "items": { "type": "string" } }
      }
    },
    "achievement": {
      "type": "object",
      "required": ["id", "name"],
      "additionalProperties": false,
      "properties": {
        "id": { "type": "string", "pattern": "^[a-z0-9_-]+$" },
        "name": { "type": "string" },
        "desc": { "type": "string", "default": "" },
        "icon": { "type": "string", "default": "" },
        "unlocked": { "type": "boolean", "default": false },
        "unlockedAt": { "type": ["string", "null"], "format": "date-time" }
      }
    },
    "journalEntry": {
      "type": "object",
      "required": ["ts", "text"],
      "additionalProperties": false,
      "properties": {
        "ts": { "type": "string", "format": "date-time" },
        "text": { "type": "string" },
        "type": { "type": "string", "enum": ["activity", "journal", "system", "claim-event", "claimed-alias", "claimed-recovery"], "default": "journal" },
        "seal": { "type": ["string", "null"] },
        "aliasId": { "type": ["string", "null"], "description": "Alias identifier for claimed entries." },
        "aliasName": { "type": ["string", "null"], "description": "Alias display name for claimed entries." },
        "linkedTo": { "type": ["string", "null"], "description": "Genesis hash of the claiming profile." },
        "claimId": { "type": ["string", "null"], "description": "Unique claim session identifier." },
        "sealBroken": { "type": "boolean", "description": "True if the source log had integrity warnings." }
      }
    },
    "credential": {
      "type": "object",
      "required": ["id", "name"],
      "properties": {
        "id": { "type": "string" },
        "name": { "type": "string" },
        "issuedAt": { "type": ["string", "null"], "format": "date-time" },
        "data": { "type": "object" }
      }
    },
    "seal": {
      "type": "object",
      "required": ["taskId", "seal", "previousSeal", "timestamp", "data", "hashAlgorithm", "nonce"],
      "additionalProperties": false,
      "properties": {
        "taskId": { "type": "string" },
        "seal": { "type": "string" },
        "previousSeal": { "type": "string", "description": "'genesis' for the first seal, otherwise the seal hash of the prior entry" },
        "timestamp": { "type": "string", "format": "date-time" },
        "data": { "description": "Arbitrary JSON-serializable task data" },
        "hashAlgorithm": { "type": "string", "enum": ["sha256", "djb2"], "description": "Algorithm used to compute this seal hash" },
        "nonce": { "type": ["integer", "number"], "description": "Random nonce consumed during seal computation, persisted for deterministic re-verification" }
      }
    },
    "auditEntry": {
      "type": "object",
      "required": ["ts", "action"],
      "additionalProperties": false,
      "properties": {
        "ts": { "type": "string", "format": "date-time" },
        "action": { "type": "string", "enum": ["seal-added", "profile-saved", "profile-imported", "alias-claimed", "recovery-claimed"] },
        "detail": { "description": "Optional action-specific data", "type": ["object", "null"] }
      }
    }
  }
};

